'use client';

import { useCallback, useEffect, useState } from 'react';
import {
  BadgeCheck,
  BookOpen,
  Brain,
  CalendarCheck,
  Crown,
  Flame,
  Gem,
  GraduationCap,
  MessageSquareText,
  Mic,
  Mountain,
  Rocket,
  Sparkles,
  Star,
  Target,
  Trophy,
} from 'lucide-react';
import {
  AccountPanel,
  AchievementsPanel,
  AppearancePanel,
  NotificationsPanel,
  ProfileDetailsPanel,
} from './panels';
import { ProfileViewShell } from '../../components/profile/ProfileViewShell';
import {
  activeMockUser,
  buildProfileAchievements,
  canView,
  getProficiencyLevelById,
  getAppearancePrefsForUser,
  getNotificationPrefsForUser,
  mockProfileForm,
  mockProfileStats,
  patchAppearancePrefsForUser,
  setNotificationPrefsForUser,
  siteContent,
  type ProfileFontSizeMode,
  type ProfileNotificationPrefs,
  type ProfileThemeMode,
} from '../../mocks';
import { useAppearanceSettings } from '../providers';
import { getAvatarFallbackInitials } from '../../lib/avatar';

export default function ProfilePage() {
  const [tab, setTab] = useState<
    'profile' | 'notifications' | 'appearance' | 'achievements' | 'account'
  >('profile');
  const [saved, setSaved] = useState(false);
  const [form, setForm] = useState({ ...mockProfileForm });
  const [notifications, setNotificationsState] = useState(() =>
    getNotificationPrefsForUser(activeMockUser.id),
  );
  const { theme, setTheme, fontSize, setFontSize } = useAppearanceSettings();

  useEffect(() => {
    setNotificationsState(getNotificationPrefsForUser(activeMockUser.id));
    const appearance = getAppearancePrefsForUser(activeMockUser.id);
    setTheme(appearance.theme);
    setFontSize(appearance.fontSize);
  }, [activeMockUser.id, setTheme, setFontSize]);

  const setNotifications = useCallback(
    (action: React.SetStateAction<typeof notifications>) => {
      setNotificationsState((prev) => {
        const next = typeof action === 'function' ? action(prev) : action;
        patchAppearancePrefsForUser(activeMockUser.id, {});
        const { patchNotificationPrefsForUser } = require('../../mocks');
        patchNotificationPrefsForUser(activeMockUser.id, next);
        return next;
      });
    },
    [activeMockUser.id],
  );
  const profileAchievements = buildProfileAchievements(mockProfileStats);
  const achievementIconMap = {
    sparkles: <Sparkles size={20} />,
    'graduation-cap': <GraduationCap size={20} />,
    'calendar-check': <CalendarCheck size={20} />,
    flame: <Flame size={20} />,
    'book-open': <BookOpen size={20} />,
    brain: <Brain size={20} />,
    'messages-square': <MessageSquareText size={20} />,
    mic: <Mic size={20} />,
    target: <Target size={20} />,
    'badge-check': <BadgeCheck size={20} />,
    star: <Star size={20} />,
    rocket: <Rocket size={20} />,
    trophy: <Trophy size={20} />,
    crown: <Crown size={20} />,
    mountain: <Mountain size={20} />,
    gem: <Gem size={20} />,
  } as const;
  const allAchievements = profileAchievements.map((achievement) => ({
    icon: achievementIconMap[achievement.icon],
    label: achievement.label,
    description: achievement.description,
    unlocked: achievement.unlocked,
  }));
  const recentUnlockedAchievements = allAchievements.filter((achievement) => achievement.unlocked).slice(-10);

  if (!canView('profile', activeMockUser.role)) return null;

  return (
    <ProfileViewShell
      title={siteContent.profile.title}
      subtitle={`${siteContent.profile.subtitle} · ${activeMockUser.role}`}
      avatar={
        activeMockUser.avatar.url ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img src={activeMockUser.avatar.url} alt="" width={72} height={72} style={{ borderRadius: '50%', objectFit: 'cover' }} />
        ) : (
          getAvatarFallbackInitials(activeMockUser.fullName)
        )
      }
      name={form.name}
      meta={`${getProficiencyLevelById(activeMockUser.proficiencyLevelId)?.code ?? '—'} · ${activeMockUser.role}`}
      badges={[
        { label: 'Upper-Intermediate' },
        { label: 'Active learner', variant: 'green' },
      ]}
      stats={[
        { value: String(mockProfileStats.wordsLearned), label: 'Words' },
        { value: String(mockProfileStats.lessonsCompleted), label: 'Lessons' },
        { value: String(mockProfileStats.streakDays), label: 'Streak' },
      ]}
      achievements={recentUnlockedAchievements}
      tab={tab}
      onTabChange={setTab}
      tabs={[
          {
            value: 'profile',
            label: 'Profile',
            panel: (
              <ProfileDetailsPanel
                form={form}
                setForm={setForm}
                saved={saved}
                viewerRole={activeMockUser.role}
                onSave={() => {
                  setSaved(true);
                  setTimeout(() => setSaved(false), 2500);
                }}
              />
            ),
          },
          {
            value: 'notifications',
            label: 'Notifications',
            panel: (
              <NotificationsPanel
                notifications={notifications}
                setNotifications={setNotifications}
              />
            ),
          },
          {
            value: 'appearance',
            label: 'Appearance',
            panel: (
              <AppearancePanel
                theme={theme}
                setTheme={setTheme}
                fontSize={fontSize}
                setFontSize={setFontSize}
              />
            ),
          },
          {
            value: 'achievements',
            label: 'Achievements',
            panel: <AchievementsPanel achievements={allAchievements} />,
          },
          {
            value: 'account',
            label: 'Account',
            panel: <AccountPanel />,
          },
      ]}
    />
  );
}
